code.C:
#include <stdio.h>
int getSum(int a, int b) {
    return a + b;
}
int main() {
    int a, b;
    printf("Enter two integers: ");
    scanf("%d %d", &a, &b);
    printf("Sum: %d\n", getSum(a, b));
    return 0;
}

